INSERT INTO `place` (`id`, `name`, `type_id`, `description`, `district_id`, `latitude`, `longitude`, `address`, `operating_info`, `image_url_1`, `image_url_2`) VALUES
  (1, 'KT&G 상상마당 부산', 1, '부산 부산진구의 KT&G 상상마당 부산은 문화 콘텐츠를 다양하게 경험할 수 있는 공간입니다. 프로그램 일정에 따라 방문 계획을 세우면 좋습니다.', 5, 35.154277104, 129.0573021838, '부산광역시 부산진구 서면로 39', '10:00~19:00 · 매주 월요일 휴관', 'https://tong.visitkorea.or.kr/cms/resource/17/3541017_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/17/3541017_image3_1.jpg'),
  (2, '유엔기념공원', 1, '유엔기념공원은 부산 남구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 7, 35.1277309389, 129.0952827131, '부산광역시 남구 유엔평화로 93 유엔기념공원', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/39/4055739_image2_1.png', 'https://tong.visitkorea.or.kr/cms/resource/39/4055739_image3_1.png'),
  (3, '비석문화마을', 1, '부산 서구에 위치한 비석문화마을은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 2, 35.0998088253, 129.0124202609, '부산광역시 서구 아미로 49 (아미동2가)', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/31/4068231_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/31/4068231_image3_1.jpg'),
  (4, '이송도전망대', 1, '이송도전망대는 부산 영도구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 4, 35.075519, 129.047956, '부산광역시 영도구 절영로 246-36 (영선동4가)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/81/3495881_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/81/3495881_image3_1.jpg'),
  (5, '밀락더마켓', 1, '부산 수영구에 위치한 밀락더마켓은 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 14, 35.1542200827, 129.1270373527, '부산광역시 수영구 민락수변로17번길 56', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/36/3495536_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/36/3495536_image3_1.jpg'),
  (6, '해리단길', 1, '해리단길은 부산 해운대구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 9, 35.1648388507, 129.1576008763, '부산 해운대구 우동 510-7', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/37/3492437_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/37/3492437_image3_1.jpg'),
  (7, '주식회사 놀핏', 1, '부산 사하구에 위치한 주식회사 놀핏은 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 10, 35.0793068504, 128.9516015875, '부산광역시 사하구 장림로93번길 74 (장림동) 맛술촌 11호', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/69/4059269_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/69/4059269_image3_1.jpg'),
  (8, '보수동 책방골목', 1, '보수동 책방골목은 부산 중구에 자리한 문화·교육 체험 공간입니다. 전시와 참여형 프로그램이 함께 운영되어 배우며 즐기기 좋습니다.', 1, 35.1031742254, 129.0272841727, '부산광역시 중구 대청로 67-1', '10:00~18:00 · 매주 월요일 휴관 · 프로그램별 요금 상이', 'https://tong.visitkorea.or.kr/cms/resource/32/4055732_image2_1.png', 'https://tong.visitkorea.or.kr/cms/resource/32/4055732_image3_1.png'),
  (9, '구상반려암 (부산 국가지질공원)', 1, '부산 부산진구의 구상반려암 (부산 국가지질공원)은 자연 학습과 휴식을 함께할 수 있는 공원입니다. 가족 단위 나들이 장소로 자주 찾는 곳입니다.', 5, 35.1630791231, 129.072147778, '부산광역시 부산진구 전포동', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (10, '더바디성형외과의원', 1, '더바디성형외과의원은 부산 부산진구에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 5, 35.1554132968823, 129.05756401242633, '부산광역시 부산진구 서면로 51 (부전동) 부산광역시 부산진구 서면로 51 4~7층', '09:00~22:00 · 연중무휴 · 유료', NULL, NULL),
  (11, '김민부전망대', 1, '부산 동구에 자리한 김민부전망대는 지역의 상징적인 장소로 꼽힙니다. 잠시 머무르며 도시의 풍경을 내려다보기 좋습니다.', 3, 35.1176994980395, 129.035345209069, '부산광역시 동구 영초윗길26번길 14 (초량동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/89/4058889_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/89/4058889_image3_1.jpg'),
  (12, '168계단', 1, '168계단은 부산 동구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 3, 35.1170894046269, 129.03533581582, '부산광역시 동구 영초길197번길 9', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/87/4058887_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/87/4058887_image3_1.jpg'),
  (13, '부산 구 백제병원', 1, '부산 동구의 부산 구 백제병원은 지역의 역사를 간직한 장소입니다. 안내판과 해설을 따라 둘러보면 그 배경을 더 깊이 이해할 수 있습니다.', 3, 35.116338835088456, 129.03914176140657, '부산광역시 동구 중앙대로209번길 16 (초량동)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/79/4058879_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/79/4058879_image3_1.jpg'),
  (14, '허심청', 1, '허심청은 부산 동래구에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 6, 35.2211550981779, 129.082686623437, '부산광역시 동래구 온천장로107번길 32 (온천동)', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/99/3329899_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/99/3329899_image3_1.jpg'),
  (15, '해운대해수욕장', 1, '부산 해운대구에 자리한 해운대해수욕장은 바다와 맞닿은 경관으로 사랑받는 곳입니다. 일출과 일몰 무렵의 풍경이 특히 인상적입니다.', 9, 35.1590840227225, 129.160278564827, '부산광역시 해운대구 해운대해변로 264 (우동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/34/3090534_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/34/3090534_image3_1.JPG'),
  (16, '에스엠비 웰니스 센터', 1, '에스엠비 웰니스 센터는 부산 기장군에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 16, 35.2588823233056, 129.24304473203, '부산광역시 기장군 일광읍 학리등대로 34', '09:00~22:00 · 연중무휴 · 유료', NULL, NULL),
  (17, '센텀시티 스파랜드', 1, '부산 해운대구의 센텀시티 스파랜드는 스파와 휴식 프로그램을 함께 즐길 수 있는 공간입니다. 방문 전 이용 요금과 운영 시간을 확인하는 것이 좋습니다.', 9, 35.16881749492334, 129.12952414849948, '부산광역시 해운대구 센텀남대로 35 (우동)', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/02/3544802_image2_1.JPEG', 'https://tong.visitkorea.or.kr/cms/resource/02/3544802_image3_1.JPEG'),
  (18, '클럽디 오아시스', 1, '클럽디 오아시스는 부산 해운대구에 있는 테마파크형 시설입니다. 다양한 즐길 거리가 모여 있어 하루를 온전히 보내기 좋습니다.', 9, 35.160042, 129.168483, '부산광역시 해운대구 달맞이길 30 엘시티', '10:00~20:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/83/3488983_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/83/3488983_image3_1.jpg'),
  (19, '부산 암남공원', 1, '부산 서구에 자리한 부산 암남공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 2, 35.0589, 129.0158, '부산광역시 서구 암남공원로 185 (암남동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/84/3498484_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/84/3498484_image3_1.jpg'),
  (20, '이기대공원 동생말전망대', 1, '이기대공원 동생말전망대는 부산 남구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 7, 35.13191, 129.121151, '부산광역시 남구 용호동 산1', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/60/3008060_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/60/3008060_image3_1.JPG'),
  (21, '문화골목', 1, '부산 남구에 위치한 문화골목은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 7, 35.136887075259736, 129.10299571620442, '부산광역시 남구 수영로334번길 36-1', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/42/3008042_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/42/3008042_image3_1.JPG'),
  (22, '망미단길', 1, '망미단길은 부산 수영구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 14, 35.172392577717005, 129.11031527497886, '부산광역시 수영구 수영동', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/50/3033450_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/50/3033450_image3_1.JPG'),
  (23, '빵천동', 1, '부산 수영구에 위치한 빵천동은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 14, 35.1417544, 129.1096096, '부산광역시 수영구 남천동 수영로408번길', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/87/3033387_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/87/3033387_image3_1.JPG'),
  (24, '서면먹자골목', 1, '서면먹자골목은 부산 부산진구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 5, 35.155834, 129.058433, '부산광역시 부산진구 부전동', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/12/3014312_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/12/3014312_image3_1.JPG'),
  (25, '민락해변공원', 1, '부산 수영구에 자리한 민락해변공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 14, 35.155361, 129.123391, '부산광역시 수영구 민락동', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/62/3014362_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/62/3014362_image3_1.JPG'),
  (26, '개금벚꽃길', 1, '개금벚꽃길은 부산 부산진구를 따라 이어지는 산책 코스입니다. 부담 없는 거리와 풍경 덕분에 산책과 러닝 모두에 적합합니다.', 5, 35.146244, 129.016413, '부산광역시 부산진구 개금동 765', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/73/3032373_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/73/3032373_image3_1.JPG'),
  (27, '황령산레포츠공원', 1, '부산 부산진구에 자리한 황령산레포츠공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 5, 35.15704, 129.07644, '부산광역시 부산진구 진남로328번길 99 (전포동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/48/3014248_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/48/3014248_image3_1.JPG'),
  (28, '강서체육공원', 1, '강서체육공원은 부산 강서구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 12, 35.20781783841302, 128.97386842118158, '부산광역시 강서구 체육공원로 43 (대저1동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/48/3015248_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/48/3015248_image3_1.JPG'),
  (29, '부산자연곤충마을', 1, '부산 강서구에 위치한 부산자연곤충마을은 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 12, 35.22155984537756, 128.9452222595901, '부산광역시 강서구 평강로 441 (대저1동)', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/08/3015208_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/08/3015208_image3_1.JPG'),
  (30, '두루팜', 1, '두루팜은 부산 강서구의 마을 자원을 활용한 체험 공간입니다. 지역 주민이 직접 운영하는 프로그램을 통해 일상과 맞닿은 부산을 만나볼 수 있습니다.', 12, 35.1835081427817, 128.89938887366966, '부산광역시 강서구 봉죽길91번길 65-37 (봉림동)', '09:00~18:00 · 프로그램별 사전 예약제 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/40/3015240_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/40/3015240_image3_1.JPG'),
  (31, '히어로테마파크 정관점', 1, '부산 기장군의 히어로테마파크 정관점은 놀이와 체험 시설을 갖춘 공간입니다. 시즌별 프로그램과 이용 요금은 사전에 확인하는 것이 좋습니다.', 16, 35.32119130482397, 129.1782791808084, '부산광역시 기장군 정관읍 정관중앙로 45 탑스퀘어 5층', '10:00~20:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/33/3015533_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/33/3015533_image3_1.JPG'),
  (32, '카덴96', 1, '카덴96은 부산 기장군에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 16, 35.28936955936168, 129.23454877480128, '부산광역시 기장군 일광읍 기장대로 1075-3', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/02/3015902_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/02/3015902_image3_1.JPG'),
  (33, '윗골공원', 1, '부산 기장군에 자리한 윗골공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 16, 35.32389935635918, 129.17761101818007, '부산광역시 기장군 정관읍 정관8로 11', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/32/3015932_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/32/3015932_image3_1.JPG'),
  (34, '몬스터파크 부산명지점', 1, '몬스터파크 부산명지점은 부산 강서구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 12, 35.094240512051556, 128.90543623892688, '부산광역시 강서구 명지국제1로 60-1 (명지동) 7층, 8층', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/00/3521300_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/00/3521300_image3_1.jpg'),
  (35, '정거마을 문화거리', 1, '부산 강서구에 위치한 정거마을 문화거리는 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 12, 35.068889, 128.852029, '부산광역시 강서구 눌차동 832', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/89/3015189_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/89/3015189_image3_1.JPG'),
  (36, '노리클럽', 1, '노리클럽은 부산 강서구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 12, 35.097899751804434, 128.91838767465714, '부산광역시 강서구 명지국제8로 234 (명지동) 8층 노리클럽', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/80/3038580_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/80/3038580_image3_1.JPG'),
  (37, '대룡마을', 1, '부산 기장군에 위치한 대룡마을은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 16, 35.37084904277479, 129.26348291402041, '부산광역시 기장군 장안읍 대룡1길 10', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/87/3015387_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/87/3015387_image3_1.JPG'),
  (38, '부산과학체험관', 1, '부산과학체험관은 부산 동구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 3, 35.12032107456868, 129.04412784872156, '부산광역시 동구 중앙대로260번길 11 (초량동) 부산과학체험관', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/78/3015978_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/78/3015978_image3_1.JPG'),
  (39, '증산공원', 1, '부산 동구에 자리한 증산공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 3, 35.137907708742524, 129.05165797671592, '부산광역시 동구 성북로36번길 46 (범일동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/57/3016757_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/57/3016757_image3_1.JPG'),
  (40, '부산역 풍물거리', 1, '부산역 풍물거리는 부산 동구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 3, 35.113557930470236, 129.04066520849508, '부산광역시 동구 중앙대로196번길 16-8 (초량동)', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/93/3016793_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/93/3016793_image3_1.JPG'),
  (41, '복천사(부산)', 1, '부산 영도구의 복천사(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 4, 35.08247958477894, 129.05050238462923, '부산광역시 영도구 산정길 41 (신선동3가)', '일출~일몰 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/66/4060066_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/66/4060066_image3_1.JPG'),
  (42, '중리항 방파제 등대', 1, '중리항 방파제 등대는 부산 영도구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 4, 35.067993, 129.064176, '부산광역시 영도구 중리남로 2-15 (동삼동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/45/3017445_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/45/3017445_image3_1.JPG'),
  (43, '정관온천', 1, '부산 기장군의 정관온천은 스파와 휴식 프로그램을 함께 즐길 수 있는 공간입니다. 방문 전 이용 요금과 운영 시간을 확인하는 것이 좋습니다.', 16, 35.32254781057412, 129.17787242339242, '부산광역시 기장군 정관읍 정관8로 16-5', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/34/3083334_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/34/3083334_image3_1.jpg'),
  (44, '다대포생태탐방로', 1, '다대포생태탐방로는 부산 사하구에 조성된 생태 공원입니다. 계절마다 바뀌는 식생과 산책로가 어우러져 가볍게 걷기 좋습니다.', 10, 35.046355897467016, 128.9680205530435, '부산광역시 사하구 몰운대1길 14 (다대동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/94/3027194_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/94/3027194_image3_1.JPG'),
  (45, '송림공원', 1, '부산 해운대구에 자리한 송림공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 9, 35.157116, 129.154126, '부산광역시 해운대구 우동 702', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/57/3027757_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/57/3027757_image3_1.JPG'),
  (46, '청사포 횟집촌', 1, '청사포 횟집촌은 부산 해운대구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 9, 35.161615, 129.193851, '부산광역시 해운대구 중동', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/27/3027527_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/27/3027527_image3_1.JPG'),
  (47, '할매탕', 1, '부산 해운대구의 할매탕은 스파와 휴식 프로그램을 함께 즐길 수 있는 공간입니다. 방문 전 이용 요금과 운영 시간을 확인하는 것이 좋습니다.', 9, 35.16305669005003, 129.16487410791876, '부산광역시 해운대구 중동2로10번길 7 (중동)', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/48/3083448_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/48/3083448_image3_1.jpg'),
  (48, '벡스코 상상체험 키즈월드', 1, '벡스코 상상체험 키즈월드는 부산 해운대구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 9, 35.16576593920963, 129.13494793474206, '부산광역시 해운대구 APEC로 30 (우동)', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/32/3083432_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/32/3083432_image3_1.jpg'),
  (49, '책마루전망대', 1, '부산 동구에 위치한 책마루전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 3, 35.138054703395184, 129.05242551737072, '부산광역시 동구 성북로36번길 54 (범일동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/12/3028512_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/12/3028512_image3_1.JPG'),
  (50, '이중섭전망대', 1, '이중섭전망대는 부산 동구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 3, 35.14059298912447, 129.05263133974444, '부산광역시 동구 증산로 168 (범일동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/46/3028546_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/46/3028546_image3_1.JPG');
INSERT INTO `place` (`id`, `name`, `type_id`, `description`, `district_id`, `latitude`, `longitude`, `address`, `operating_info`, `image_url_1`, `image_url_2`) VALUES
  (51, '대항항 포진지 동굴', 1, '부산 강서구에 위치한 대항항 포진지 동굴은 독특한 지형으로 알려진 자연 명소입니다. 탐방로를 따라 안전하게 둘러볼 수 있습니다.', 12, 35.0143, 128.8268, '부산광역시 강서구 가덕해안로1212번길 48-1 (대항동)', '상시 개방 · 기상 악화 시 통제 · 무료', NULL, NULL),
  (52, '호천마을', 1, '호천마을은 부산 부산진구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 5, 35.1442420605489, 129.051214140349, '부산광역시 부산진구 엄광로 491 (범천동)', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/88/3496988_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/88/3496988_image3_1.jpg'),
  (53, '소망계단 모노레일', 1, '부산 서구에 위치한 소망계단 모노레일은 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 2, 35.114443741372696, 129.02473782396245, '부산광역시 서구 동대신동2가', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/43/3545343_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/43/3545343_image3_1.jpg'),
  (54, '부네치아 선셋 전망대', 1, '부네치아 선셋 전망대는 부산 사하구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 10, 35.0792685405299, 128.95186067301356, '부산광역시 사하구 장림로93번길 72 (장림동) 일원', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/81/3544081_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/81/3544081_image3_1.jpg'),
  (55, '라보드 우든보트', 1, '부산 영도구에 자리한 라보드 우든보트에서는 바다를 무대로 한 레저 활동을 직접 체험할 수 있습니다. 계절과 기상에 따라 운영 프로그램이 달라집니다.', 4, 35.0926530954171, 129.051455492089, '부산광역시 영도구 나팔꽃길 33 (봉래동5가)', '10:00~18:00 · 기상 상황에 따라 운영 변동 · 사전 예약 권장', 'https://tong.visitkorea.or.kr/cms/resource/49/3545949_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/49/3545949_image3_1.jpg'),
  (56, '금빛노을브릿지', 1, '금빛노을브릿지는 부산 북구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 8, 35.2097843, 129.0028719, '부산광역시 북구 낙동대로 1769 (구포동) ~낙동강 화명생태공원 (연꽃단지 입구)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/02/3545402_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/02/3545402_image3_1.jpg'),
  (57, '백운포체육공원', 1, '부산 남구의 백운포체육공원은 놀이와 체험 시설을 갖춘 공간입니다. 시즌별 프로그램과 이용 요금은 사전에 확인하는 것이 좋습니다.', 7, 35.10247535972112, 129.11156975182783, '부산광역시 남구 백운포로 64 (용호동)', '10:00~20:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/57/3060957_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/57/3060957_image3_1.JPG'),
  (58, '키위키즈랜드', 1, '키위키즈랜드는 부산 기장군에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 16, 35.32126709863031, 129.2356423343507, '부산광역시 기장군 장안읍 정관로 1142 힐탑프리미엄아울렛 B1', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/86/3060786_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/86/3060786_image3_1.JPG'),
  (59, '부산정중앙공원', 1, '부산 부산진구에 자리한 부산정중앙공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 5, 35.170371, 129.036929, '부산광역시 부산진구 부암동 520-3', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/64/3300664_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/64/3300664_image3_1.jpg'),
  (60, '국립청소년생태센터', 1, '국립청소년생태센터는 부산 사하구에 자리한 문화·교육 체험 공간입니다. 전시와 참여형 프로그램이 함께 운영되어 배우며 즐기기 좋습니다.', 10, 35.112797795145575, 128.94817355829102, '부산광역시 사하구 낙동남로1233번길 43 (하단동) 국립청소년생태센터', '10:00~18:00 · 매주 월요일 휴관 · 프로그램별 요금 상이', 'https://tong.visitkorea.or.kr/cms/resource/61/3336061_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/61/3336061_image3_1.jpg'),
  (61, '을숙도 들락날락', 1, '부산 사하구에 위치한 을숙도 들락날락은 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 10, 35.109499, 128.944937, '부산광역시 사하구 낙동남로1233번길 25 (하단동)', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/86/3350186_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/86/3350186_image3_1.jpg'),
  (62, '부산광역시 119안전체험관', 1, '부산광역시 119안전체험관은 부산 동래구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 6, 35.21790195815417, 129.0742473594401, '부산광역시 동래구 우장춘로 117 (온천동)', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/36/3070636_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/36/3070636_image3_1.JPG'),
  (63, '해월전망대', 1, '부산 해운대구에 위치한 해월전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 9, 35.155883, 129.182644, '부산광역시 해운대구 중동 산42-66', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (64, '태종대 오션플라잉 테마파크', 1, '태종대 오션플라잉 테마파크는 부산 영도구에 있는 테마파크형 시설입니다. 다양한 즐길 거리가 모여 있어 하루를 온전히 보내기 좋습니다.', 4, 35.06083536151677, 129.07854368510672, '부산광역시 영도구 태종로836번길 55 (동삼동)', '10:00~20:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/42/4017042_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/42/4017042_image3_1.jpg'),
  (65, 'BIFF 광장', 1, '부산 중구에 위치한 BIFF 광장은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 1, 35.0980089584166, 129.032004281096, '부산광역시 중구 구덕로 지하44 (남포동5가)', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/19/3493419_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/19/3493419_image3_1.jpg'),
  (66, '센텀 APEC나루공원', 1, '센텀 APEC나루공원은 부산 해운대구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 9, 35.167908247558, 129.127317311652, '부산광역시 해운대구 수영강변대로 85 (우동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/21/3492421_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/21/3492421_image3_1.jpg'),
  (67, '[부산 갈맷길] 5코스', 1, '부산 사하구에 위치한 [부산 갈맷길] 5코스는 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 10, 35.1065, 128.9575, '부산광역시 사하구 하단동 낙동강 하굿둑~천가교', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/14/3589714_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/14/3589714_image3_1.jpg'),
  (68, '하버요가&무브먼트', 1, '하버요가&무브먼트는 부산 수영구에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 14, 35.1532751974826, 129.116563768469, '부산광역시 수영구 광남로 129 (광안동)', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/33/4041433_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/33/4041433_image3_1.jpg'),
  (69, '금강암(부산)', 1, '부산 금정구의 금강암(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 11, 35.2818122265257, 129.065264562003, '부산광역시 금정구 범어사로 254', '일출~일몰 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/09/3552409_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/09/3552409_image3_1.jpg'),
  (70, '부산북항 친수공원', 1, '부산북항 친수공원은 부산 동구를 따라 이어지는 산책 코스입니다. 부담 없는 거리와 풍경 덕분에 산책과 러닝 모두에 적합합니다.', 3, 35.114419907321064, 129.04662207968232, '부산광역시 동구 이순신대로 164 (초량동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/25/3454125_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/25/3454125_image3_1.JPG'),
  (71, '영도 하늘전망대', 1, '부산 영도구에 위치한 영도 하늘전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 4, 35.0719, 129.0547, '부산광역시 영도구 동삼동 628-66', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/68/3498668_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/68/3498668_image3_1.jpg'),
  (72, '젖병등대', 1, '젖병등대는 부산 기장군의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 16, 35.2137870972648, 129.223051745362, '부산광역시 기장군 기장읍 연화리 297-5', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/19/3494119_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/19/3494119_image3_1.jpg'),
  (73, '부산남항', 1, '부산 영도구에 자리한 부산남항은 바다와 맞닿은 경관으로 사랑받는 곳입니다. 일출과 일몰 무렵의 풍경이 특히 인상적입니다.', 4, 35.09186201794041, 129.03721411073323, '부산광역시 영도구 대평북로 6 (대교동1가)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/06/3498706_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/06/3498706_image3_1.jpg'),
  (74, '테이블플라워', 1, '테이블플라워는 부산 영도구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 4, 35.07638429108179, 129.04763906754965, '부산광역시 영도구 절영로 248-1 (영선동4가)', '10:00~19:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/04/3466704_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/04/3466704_image3_1.jpg'),
  (75, '청학배수지 전망대', 1, '부산 영도구에 위치한 청학배수지 전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 4, 35.088351580481, 129.060042641103, '부산광역시 영도구 와치로 36', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/47/3524947_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/47/3524947_image3_1.jpg'),
  (76, '충렬사(부산)', 1, '충렬사(부산)은 부산 동래구에 남아 있는 역사 유적입니다. 부산이 지나온 시간의 흔적을 현장에서 직접 확인할 수 있습니다.', 6, 35.2013, 129.096, '부산광역시 동래구 충렬대로 347 (안락동)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/85/3492185_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/85/3492185_image3_1.jpg'),
  (77, '문화공감 수정(부산 수정동 일본식 가옥)', 1, '부산 동구의 문화공감 수정(부산 수정동 일본식 가옥)은 지역의 역사를 간직한 장소입니다. 안내판과 해설을 따라 둘러보면 그 배경을 더 깊이 이해할 수 있습니다.', 3, 35.1255545014429, 129.042636366052, '부산광역시 동구 홍곡로 75 (수정동)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/14/4003214_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/14/4003214_image3_1.jpg'),
  (78, '천성항 방파제등대', 1, '천성항 방파제등대는 부산 강서구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 12, 35.0303, 128.8111, '부산광역시 강서구 천성동 838', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/43/3491943_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/43/3491943_image3_1.jpg'),
  (79, '부산 어린이대공원', 1, '부산 부산진구에 자리한 부산 어린이대공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 5, 35.1872173954517, 129.04264985908, '부산광역시 부산진구 새싹로 295', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/15/3512315_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/15/3512315_image3_1.jpg'),
  (80, '오륙도 등대', 1, '오륙도 등대는 부산 남구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 7, 35.0911636101177, 129.126886338426, '부산광역시 남구 오륙도로 130 (용호동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/92/3496792_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/92/3496792_image3_1.jpg'),
  (81, '영도대교', 1, '부산 영도구에 위치한 영도대교에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 4, 35.0956, 129.0365, '부산광역시 영도구 대교동1가', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/70/3495570_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/70/3495570_image3_1.jpg'),
  (82, '충렬탑(부산)', 1, '충렬탑(부산)은 부산 동래구에 세워진 기념 명소입니다. 주변 조망과 함께 지역이 기억하는 이야기를 마주할 수 있습니다.', 6, 35.2011723080822, 129.096111152225, '부산광역시 동래구 충렬대로 345 (안락동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/09/3495509_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/09/3495509_image3_1.jpg'),
  (83, '몰운대(부산)', 1, '부산 사하구에 자리한 몰운대(부산)은 바다와 맞닿은 경관으로 사랑받는 곳입니다. 일출과 일몰 무렵의 풍경이 특히 인상적입니다.', 10, 35.0405, 128.9701, '부산광역시 사하구 다대동', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/30/3506330_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/30/3506330_image3_1.jpg'),
  (84, '오륙도 (부산 국가지질공원)', 1, '오륙도 (부산 국가지질공원)은 부산 남구의 바다를 대표하는 명소입니다. 탁 트인 수평선과 해안 풍경이 사계절 내내 방문객을 맞이합니다.', 7, 35.0920024009764, 129.126919645422, '부산광역시 남구 오륙도로 137', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/20/3496820_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/20/3496820_image3_1.jpg'),
  (85, '용두산공원', 1, '부산 중구의 용두산공원은 자연 학습과 휴식을 함께할 수 있는 공원입니다. 가족 단위 나들이 장소로 자주 찾는 곳입니다.', 1, 35.1004440914145, 129.032664302294, '부산광역시 중구 용두산길 37-55', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/34/3494834_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/34/3494834_image3_1.jpg'),
  (86, '금정산성', 1, '금정산성은 부산 금정구에 남아 있는 역사 유적입니다. 부산이 지나온 시간의 흔적을 현장에서 직접 확인할 수 있습니다.', 11, 35.25535146977595, 129.05241630440221, '부산광역시 금정구 북문로 78-5 (금성동)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/45/3494945_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/45/3494945_image3_1.jpg'),
  (87, '부산진성공원', 1, '부산 동구에 자리한 부산진성공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 3, 35.135868230927, 129.061096784383, '부산광역시 동구 자성로 99', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/74/3496874_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/74/3496874_image3_1.jpg'),
  (88, '해동용궁사', 1, '해동용궁사는 부산 기장군에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 16, 35.1882428912293, 129.223530192843, '부산광역시 기장군 기장읍 용궁길 86', '일출~일몰 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/35/3499335_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/35/3499335_image3_1.jpg'),
  (89, '영도 등대', 1, '부산 영도구에 위치한 영도 등대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 4, 35.0523536391521, 129.092335072703, '부산광역시 영도구 전망로 181', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/57/3495557_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/57/3495557_image3_1.jpg'),
  (90, '청사포', 1, '청사포는 부산 해운대구의 바다를 대표하는 명소입니다. 탁 트인 수평선과 해안 풍경이 사계절 내내 방문객을 맞이합니다.', 9, 35.1604039113018, 129.192189444504, '부산광역시 해운대구 중동', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/30/3495930_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/30/3495930_image3_1.jpg'),
  (91, '봉래산(부산)', 1, '부산 영도구에 위치한 봉래산(부산)은 등산과 산책을 함께 즐길 수 있는 자연 명소입니다. 정상부에서는 부산 시가지와 바다가 한눈에 들어옵니다.', 4, 35.0822, 129.0553, '부산광역시 영도구 청학동', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', 'https://tong.visitkorea.or.kr/cms/resource/65/3503265_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/65/3503265_image3_1.jpg'),
  (92, '낙동강하구에코센터', 1, '낙동강하구에코센터는 부산 사하구를 따라 이어지는 산책 코스입니다. 부담 없는 거리와 풍경 덕분에 산책과 러닝 모두에 적합합니다.', 10, 35.1043892335363, 128.945866728608, '부산광역시 사하구 낙동남로 1240', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/22/3495822_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/22/3495822_image3_1.jpg'),
  (93, '조방해수탕', 1, '부산 부산진구의 조방해수탕은 스파와 휴식 프로그램을 함께 즐길 수 있는 공간입니다. 방문 전 이용 요금과 운영 시간을 확인하는 것이 좋습니다.', 5, 35.1418120027646, 129.062543707148, '부산광역시 부산진구 자유평화로37번길 15-19', '09:00~22:00 · 연중무휴 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/29/3496929_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/29/3496929_image3_1.jpg'),
  (94, '삼락생태공원', 1, '삼락생태공원은 부산 사상구에 조성된 생태 공원입니다. 계절마다 바뀌는 식생과 산책로가 어우러져 가볍게 걷기 좋습니다.', 15, 35.1691043434193, 128.973176285884, '부산 사상구 삼락동 29-46', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/90/3497090_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/90/3497090_image3_1.jpg'),
  (95, '전포카페거리', 1, '부산 부산진구에 위치한 전포카페거리는 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 5, 35.15542, 129.067338, '부산광역시 부산진구 동천로 92 (전포동)', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/60/3496960_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/60/3496960_image3_1.jpg'),
  (96, '이기대', 1, '이기대는 부산 남구의 바다를 대표하는 명소입니다. 탁 트인 수평선과 해안 풍경이 사계절 내내 방문객을 맞이합니다.', 7, 35.115449, 129.123566, '부산광역시 남구 용호동', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/02/3496802_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/02/3496802_image3_1.jpg'),
  (97, '초량 이바구길', 1, '부산 동구에 위치한 초량 이바구길은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 3, 35.1169, 129.0367, '부산 동구 초량동 865-48', '상시 개방 · 점포별 운영 시간 상이', 'https://tong.visitkorea.or.kr/cms/resource/42/3496842_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/42/3496842_image3_1.jpg'),
  (98, '부산시민공원', 1, '부산시민공원은 부산 부산진구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 5, 35.1681, 129.0574, '부산광역시 부산진구 시민공원로 73 (범전동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/05/3497005_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/05/3497005_image3_1.jpg'),
  (99, '흰여울문화마을', 1, '부산 영도구에 위치한 흰여울문화마을에서는 어촌·농촌의 생활 문화를 가까이에서 체험할 수 있습니다. 가족 단위 방문객에게 특히 인기가 많은 곳입니다.', 4, 35.0783, 129.0453, '부산광역시 영도구 영선동4가 605-3', '09:00~18:00 · 프로그램별 사전 예약제 · 유료', 'https://tong.visitkorea.or.kr/cms/resource/74/3495874_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/74/3495874_image3_1.jpg'),
  (100, '칠암항', 1, '칠암항은 부산 기장군의 바다를 대표하는 명소입니다. 탁 트인 수평선과 해안 풍경이 사계절 내내 방문객을 맞이합니다.', 16, 35.2985805894268, 129.260259786681, '부산광역시 기장군 일광면 문오성길 510', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/10/3494110_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/10/3494110_image3_1.jpg');
INSERT INTO `place` (`id`, `name`, `type_id`, `description`, `district_id`, `latitude`, `longitude`, `address`, `operating_info`, `image_url_1`, `image_url_2`) VALUES
  (101, '묘관음사', 1, '부산 기장군의 묘관음사는 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 16, 35.3228250674329, 129.266244656908, '부산광역시 기장군 장안읍 해맞이로 253-38', '일출~일몰 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/72/3494272_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/72/3494272_image3_1.jpg'),
  (102, '가야공원', 1, '가야공원은 부산 부산진구에 조성된 생태 공원입니다. 계절마다 바뀌는 식생과 산책로가 어우러져 가볍게 걷기 좋습니다.', 5, 35.1483050312523, 129.027660668177, '부산광역시 부산진구 엄광로 118 (가야동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/10/3495510_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/10/3495510_image3_1.jpg'),
  (103, '온천천시민공원', 1, '부산 연제구에 자리한 온천천시민공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 13, 35.193006, 129.092543, '부산광역시 연제구 온천천남로 39 (연산동)', '상시 개방 · 연중무휴 · 무료', 'https://tong.visitkorea.or.kr/cms/resource/18/3498718_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/18/3498718_image3_1.jpg'),
