  (236, '키자니아 부산', 1, '키자니아 부산은 부산 해운대구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 9, 35.1699003261, 129.1283187187, '부산광역시 해운대구 센텀4로 15 센텀시티 몰', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/33/3526933_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/33/3526933_image3_1.jpg'),
  (237, '황령산 전망대', 1, '부산 남구에 위치한 황령산 전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 7, 35.1579341561, 129.0827285679, '부산광역시 남구 황령산로 391-39 (대연동)', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (238, '해운대 그린레일웨이 (미포~송정 구간)', 1, '해운대 그린레일웨이 (미포~송정 구간)은 부산 해운대구를 따라 이어지는 산책 코스입니다. 부담 없는 거리와 풍경 덕분에 산책과 러닝 모두에 적합합니다.', 9, 35.1612857933, 129.1914273569, '부산광역시 해운대구 청사포로 116 (중동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/37/2822337_image2_1.png', 'http://tong.visitkorea.or.kr/cms/resource/37/2822337_image3_1.png'),
  (239, '낙동강하구 (부산 국가지질공원)', 1, '부산 사하구에 자리한 낙동강하구 (부산 국가지질공원)은 바다와 맞닿은 경관으로 사랑받는 곳입니다. 일출과 일몰 무렵의 풍경이 특히 인상적입니다.', 10, 35.104551505, 128.9460085869, '부산광역시 사하구 낙동남로 1240 (하단동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/37/3029337_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/37/3029337_image3_1.jpg'),
  (240, '민주공원', 1, '민주공원은 부산 중구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 1, 35.1093802515, 129.0281096457, '부산광역시 중구 민주공원길 19 (영주동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/47/3498447_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/47/3498447_image3_1.jpg'),
  (241, '부산기후변화체험교육관', 1, '부산 북구의 부산기후변화체험교육관에서는 다양한 주제의 체험과 전시를 만날 수 있습니다. 프로그램에 따라 사전 예약이 필요할 수 있습니다.', 8, 35.2329549282, 129.0081635592, '부산광역시 북구 학사로 118 (화명동)', '10:00~18:00 · 매주 월요일 휴관 · 프로그램별 요금 상이', 'http://tong.visitkorea.or.kr/cms/resource/07/3442507_image2_1.jpeg', 'http://tong.visitkorea.or.kr/cms/resource/07/3442507_image3_1.jpeg'),
  (242, '다대포 꿈의 낙조분수', 1, '다대포 꿈의 낙조분수는 부산 사하구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 10, 35.0463945293, 128.9680471374, '부산광역시 사하구 몰운대1길 14 (다대동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/08/3506208_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/08/3506208_image3_1.jpg'),
  (243, '대천공원', 1, '부산 해운대구에 자리한 대천공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 9, 35.1813775511, 129.1678566312, '부산광역시 해운대구 장산로 331-18 (좌동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/42/2875842_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/42/2875842_image3_1.JPG'),
  (244, '달맞이동산', 1, '달맞이동산은 부산 해운대구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 9, 35.1571305311, 129.1821532774, '부산광역시 해운대구 달맞이길 184 (중동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/24/2875824_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/24/2875824_image3_1.JPG'),
  (245, '화명수목원', 1, '부산 북구의 화명수목원은 자연 학습과 휴식을 함께할 수 있는 공원입니다. 가족 단위 나들이 장소로 자주 찾는 곳입니다.', 8, 35.2510535364, 129.0426767218, '부산광역시 북구 산성로 299 (화명동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/41/3497041_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/41/3497041_image3_1.jpg'),
  (246, '녹산고향동산', 1, '녹산고향동산은 부산 강서구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 12, 35.154317052, 128.8860013488, '부산광역시 강서구 범방4로 132', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/14/2867914_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/14/2867914_image3_1.JPG'),
  (247, '통일아시아드 공원', 1, '부산 사하구에 자리한 통일아시아드 공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 10, 35.0594543994, 128.9800346295, '부산광역시 사하구 다대동 1585', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/50/2867550_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/50/2867550_image3_1.JPG'),
  (248, 'F1963', 1, 'F1963은 부산 수영구에 자리한 문화·교육 체험 공간입니다. 전시와 참여형 프로그램이 함께 운영되어 배우며 즐기기 좋습니다.', 14, 35.1767854293, 129.1155140878, '부산광역시 수영구 구락로123번길 20', '10:00~18:00 · 매주 월요일 휴관 · 프로그램별 요금 상이', 'http://tong.visitkorea.or.kr/cms/resource/61/3350961_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/61/3350961_image3_1.jpg'),
  (249, '남선창고터', 1, '부산 동구의 남선창고터는 지역의 역사를 간직한 장소입니다. 안내판과 해설을 따라 둘러보면 그 배경을 더 깊이 이해할 수 있습니다.', 3, 35.1167962983, 129.0395112298, '부산광역시 동구 초량로13번길 53 (초량동)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/79/3070879_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/79/3070879_image3_1.JPG'),
  (250, '남도해양열차 에스트레인(S-train)', 1, '남도해양열차 에스트레인(S-train)은 부산 동구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 3, 35.1152715223, 129.0424332391, '부산광역시 동구 중앙대로 206', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/78/3070878_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/78/3070878_image3_1.JPG');
INSERT INTO `place` (`id`, `name`, `type_id`, `description`, `district_id`, `latitude`, `longitude`, `address`, `operating_info`, `image_url_1`, `image_url_2`) VALUES
  (251, '성암사(부산)', 1, '부산 남구의 성암사(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 7, 35.1456799238, 129.0800957995, '부산광역시 남구 진남로210번길 58-15 (문현동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/32/3070632_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/32/3070632_image3_1.JPG'),
  (252, '금강식물원', 1, '금강식물원은 부산 금정구에 조성된 생태 공원입니다. 계절마다 바뀌는 식생과 산책로가 어우러져 가볍게 걷기 좋습니다.', 11, 35.2264763727, 129.077063292, '부산광역시 금정구 장전동 산 43-1', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/04/3070504_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/04/3070504_image3_1.JPG'),
  (253, '광안리해변 테마거리', 1, '부산 수영구에 위치한 광안리해변 테마거리는 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 14, 35.1551657503, 129.1221363273, '부산광역시 수영구 민락동 (민락동)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/42/3071042_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/42/3071042_image3_1.JPG'),
  (254, '부산동명불원', 1, '부산동명불원은 부산 남구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 7, 35.1189694636, 129.1038166893, '부산광역시 남구 동명로 57 (용당동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/69/3070669_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/69/3070669_image3_1.JPG'),
  (255, '죽도공원', 1, '부산 해운대구에 자리한 죽도공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 9, 35.1799561988, 129.206133898, '부산광역시 해운대구 송정해변로 1-23', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/88/3019388_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/88/3019388_image3_1.JPG'),
  (256, '삼진어묵 체험·역사과학관', 1, '삼진어묵 체험·역사과학관은 부산 영도구에 자리한 문화·교육 체험 공간입니다. 전시와 참여형 프로그램이 함께 운영되어 배우며 즐기기 좋습니다.', 4, 35.0928101531, 129.0427254928, '부산광역시 영도구 절영로7번길 41-1 (봉래동2가)', '10:00~18:00 · 매주 월요일 휴관 · 프로그램별 요금 상이', 'http://tong.visitkorea.or.kr/cms/resource/64/3399264_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/64/3399264_image3_1.jpg'),
  (257, '물빛색스튜디오', 1, '부산 강서구에 위치한 물빛색스튜디오는 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 12, 35.2093737159, 128.979783344, '부산광역시 강서구 체육공원로6번길 139-28 (대저1동)', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/64/3491264_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/64/3491264_image3_1.jpg'),
  (258, '법륜사(부산)', 1, '법륜사(부산)은 부산 동래구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 6, 35.2036235793, 129.0879435276, '부산광역시 동래구 동래로 160 (칠산동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/97/3081197_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/97/3081197_image3_1.JPG'),
  (259, '용호별빛공원', 1, '부산 남구에 자리한 용호별빛공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 7, 35.1322571676, 129.1201732372, '부산광역시 남구 분포로 66-40', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/33/2822233_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/33/2822233_image3_1.jpg'),
  (260, '승학산', 1, '승학산은 부산 사하구의 산림 명소입니다. 도심에서 가까우면서도 숲길과 능선을 따라 걷는 즐거움이 있는 곳입니다.', 10, 35.1310381466, 128.9851266839, '부산광역시 사하구 하단동', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', 'http://tong.visitkorea.or.kr/cms/resource/46/3029246_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/46/3029246_image3_1.jpg'),
  (261, '부산 복천동 고분군', 1, '부산 동래구의 부산 복천동 고분군은 지역의 역사를 간직한 장소입니다. 안내판과 해설을 따라 둘러보면 그 배경을 더 깊이 이해할 수 있습니다.', 6, 35.2068732659, 129.0906820891, '부산광역시 동래구 복천로 66', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/94/3083494_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/94/3083494_image3_1.JPG'),
  (262, '관수옥과 초량왜관 터', 1, '관수옥과 초량왜관 터는 부산 중구에 남아 있는 역사 유적입니다. 부산이 지나온 시간의 흔적을 현장에서 직접 확인할 수 있습니다.', 1, 35.1005396593, 129.0327483723, '부산광역시 중구 용두산길 37-55 (광복동2가)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/24/3049224_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/24/3049224_image2_1.JPG'),
  (263, '중리노을전망대', 1, '부산 영도구에 위치한 중리노을전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 4, 35.0692381886, 129.0643270354, '부산광역시 영도구 동삼동 632-3', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/53/3455153_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/53/3455153_image3_1.jpg'),
  (264, '오륙도해맞이공원', 1, '오륙도해맞이공원은 부산 남구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 7, 35.1016495355, 129.1230988205, '부산광역시 남구 용호동 950-1', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (265, '씨라이프부산아쿠아리움', 1, '부산 해운대구의 씨라이프부산아쿠아리움은 놀이와 체험 시설을 갖춘 공간입니다. 시즌별 프로그램과 이용 요금은 사전에 확인하는 것이 좋습니다.', 9, 35.159196575, 129.1610328343, '부산광역시 해운대구 해운대해변로 266 (중동)', '10:00~20:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/09/3020609_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/09/3020609_image3_1.jpg'),
  (266, '해운대리버크루즈', 1, '해운대리버크루즈는 부산 해운대구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 9, 35.1679171964, 129.1273244146, '부산광역시 해운대구 수영강변대로 85 (우동)', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/26/3041326_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/26/3041326_image3_1.JPG'),
  (267, '국제시장 먹자골목', 1, '부산 중구에 위치한 국제시장 먹자골목은 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 1, 35.1011311741, 129.0280793175, '부산광역시 중구 중구로 36', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/30/3476830_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/30/3476830_image3_1.jpg'),
  (268, '감천사(부산)', 1, '감천사(부산)은 부산 연제구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 13, 35.1833036953, 129.0912632411, '부산광역시 연제구 묘봉산로 40 (연산동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/20/3476820_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/20/3476820_image3_1.jpg'),
  (269, '청학수변공원', 1, '부산 영도구에 자리한 청학수변공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 4, 35.0977293865, 129.0611626448, '부산광역시 영도구 청학동 217-43', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/30/3080230_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/30/3080230_image3_1.JPG'),
  (270, '중앙해수랜드', 1, '중앙해수랜드는 부산 남구에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 7, 35.125627178, 129.1106575793, '부산광역시 남구 용호로 64', '09:00~22:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/98/3476698_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/98/3476698_image3_1.jpg'),
  (271, '대천천', 1, '부산 북구에 위치한 대천천은 등산과 산책을 함께 즐길 수 있는 자연 명소입니다. 정상부에서는 부산 시가지와 바다가 한눈에 들어옵니다.', 8, 35.2422290925, 129.019201232, '부산광역시 북구 화명동', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', 'http://tong.visitkorea.or.kr/cms/resource/60/3476760_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/60/3476760_image3_1.jpg'),
  (272, '해운대온천센터', 1, '해운대온천센터는 부산 해운대구에 위치한 휴식·웰니스 공간입니다. 여행 중 지친 몸을 재정비하기 좋은 시설을 갖추고 있습니다.', 9, 35.1634406103, 129.1645768542, '부산광역시 해운대구 중동2로 16 (중동)', '09:00~22:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/17/3026517_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/17/3026517_image3_1.JPG'),
  (273, '색채마을', 1, '부산 중구에 위치한 색채마을에서는 어촌·농촌의 생활 문화를 가까이에서 체험할 수 있습니다. 가족 단위 방문객에게 특히 인기가 많은 곳입니다.', 1, 35.1070333171, 129.0294707029, '부산광역시 중구 망양로 327-1 (대청동4가)', '09:00~18:00 · 프로그램별 사전 예약제 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/23/3064923_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/23/3064923_image3_1.JPG'),
  (274, '자갈치 크루즈', 1, '자갈치 크루즈는 부산 중구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 1, 35.0967261783, 129.0317124553, '부산광역시 중구 자갈치해안로 60 (남포동4가)', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/18/3064818_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/18/3064818_image3_1.JPG'),
  (275, '대각사(부산)', 1, '부산 중구의 대각사(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 1, 35.1010840062, 129.0307152012, '부산광역시 중구 광복중앙로 19 (신창동1가)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/39/3049439_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/39/3049439_image3_1.JPG'),
  (276, '수리조선소길', 1, '수리조선소길은 부산 영도구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 4, 35.0923794753, 129.033490197, '부산광역시 영도구 대평로 42 (대평동2가)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/19/3031919_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/19/3031919_image3_1.JPG'),
  (277, '경상좌수영성지', 1, '부산 수영구의 경상좌수영성지는 지역의 역사를 간직한 장소입니다. 안내판과 해설을 따라 둘러보면 그 배경을 더 깊이 이해할 수 있습니다.', 14, 35.1743106361, 129.1117117085, '부산광역시 수영구 수영성로 43 (수영동)', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/02/3476802_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/02/3476802_image3_1.jpg'),
  (278, '낙조정', 1, '낙조정은 부산 사하구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 10, 35.1096647018, 128.9394840158, '부산광역시 사하구 낙동남로 1169 (하단동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/23/3027423_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/23/3027423_image3_1.JPG'),
  (279, '금정산성 동문', 1, '부산 금정구의 금정산성 동문은 지역의 역사를 간직한 장소입니다. 안내판과 해설을 따라 둘러보면 그 배경을 더 깊이 이해할 수 있습니다.', 11, 35.2453406867, 129.0642277794, '부산광역시 금정구 장전동 산 2-3', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/77/3027077_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/77/3027077_image3_1.JPG'),
  (280, '전포공구길', 1, '전포공구길은 부산 부산진구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 5, 35.1587281711, 129.0642801508, '부산광역시 부산진구 서전로37번길 20', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/78/2994078_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/78/2994078_image3_1.JPG'),
  (281, '부산 자갈치 양곱창 골목', 1, '부산 중구에 위치한 부산 자갈치 양곱창 골목은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 1, 35.0973677005, 129.0277461155, '부산광역시 중구 구덕로 73 (남포동5가)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/37/3049537_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/37/3049537_image3_1.JPG'),
  (282, '청량사(부산)', 1, '청량사(부산)은 부산 강서구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 12, 35.117757865, 128.9190855715, '부산광역시 강서구 제도로 29', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/85/3041185_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/85/3041185_image3_1.JPG'),
  (283, '영주암(부산)', 1, '부산 수영구의 영주암(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 14, 35.1766545764, 129.0986683346, '부산광역시 수영구 망미배산로76번나길 15 (망미동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/17/3032417_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/17/3032417_image3_1.JPG'),
  (284, '마하사(부산)', 1, '마하사(부산)은 부산 연제구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 13, 35.1639058017, 129.0876863061, '부산광역시 연제구 봉수로 138', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/32/3031232_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/32/3031232_image3_1.JPG'),
  (285, '금용암(부산)', 1, '부산 연제구의 금용암(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 13, 35.1916075512, 129.049663856, '부산광역시 연제구 성지곡로 111 (거제동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/77/3031277_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/77/3031277_image3_1.JPG'),
  (286, '망산도·유주암', 1, '망산도·유주암은 부산 강서구에 남아 있는 역사 유적입니다. 부산이 지나온 시간의 흔적을 현장에서 직접 확인할 수 있습니다.', 12, 35.0967250919, 128.8209252451, '부산광역시 강서구 송정동', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/91/3031391_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/91/3031391_image3_1.JPG'),
  (287, '해운대 관광특구', 1, '부산 해운대구에 자리한 해운대 관광특구는 관광 인프라가 집중된 구역입니다. 도보 이동만으로도 다양한 명소를 둘러볼 수 있습니다.', 9, 35.1584383046, 129.1598690678, '부산광역시 해운대구 우동, 중동, 송정동, 재송동 센텀시티 지역', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/68/3026468_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/68/3026468_image3_1.JPG'),
  (288, '광복로패션거리', 1, '광복로패션거리는 부산 중구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 1, 35.0986398717, 129.0327400915, '부산광역시 중구 광복로 72-1 (광복동2가)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/11/3049611_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/11/3049611_image3_1.JPG'),
  (289, '내원정사(부산)', 1, '부산 서구의 내원정사(부산)은 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 2, 35.1265891347, 129.0117550433, '부산광역시 서구 엄광산로40번길 80 (서대신동3가)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/55/3031655_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/55/3031655_image3_1.JPG'),
  (290, '청사포 기찻길', 1, '청사포 기찻길은 부산 해운대구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 9, 35.1581969059, 129.172851279, '부산광역시 해운대구 달맞이길62번길 13 (중동)', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/53/3027653_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/53/3027653_image3_1.JPG'),
  (291, '용두산 자갈치 관광특구', 1, '부산 중구에 자리한 용두산 자갈치 관광특구는 관광 인프라가 집중된 구역입니다. 도보 이동만으로도 다양한 명소를 둘러볼 수 있습니다.', 1, 35.0966650543, 129.0306014426, '부산광역시 중구 자갈치해안로 52 (남포동4가)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/46/3049246_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/46/3049246_image3_1.JPG'),
  (292, '관음사(부산)', 1, '관음사(부산)은 부산 사하구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 10, 35.1088376838, 128.9758364301, '부산광역시 사하구 제석로79번길 33 (당리동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/10/2790710_image2_1.JPG', 'http://tong.visitkorea.or.kr/cms/resource/10/2790710_image3_1.JPG'),
  (293, '부산 송도해수욕장', 1, '부산 서구에 자리한 부산 송도해수욕장은 바다와 맞닿은 경관으로 사랑받는 곳입니다. 일출과 일몰 무렵의 풍경이 특히 인상적입니다.', 2, 35.0739256715, 129.016458847, '부산광역시 서구 송도해변로 100', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/86/2504686_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/86/2504686_image3_1.jpg'),
  (294, '스포원파크재난안전체험관', 1, '스포원파크재난안전체험관은 부산 금정구에 있는 이색 테마 체험 공간입니다. 다른 곳에서 보기 어려운 콘텐츠로 방문객의 발길을 끄는 장소입니다.', 11, 35.2918223435, 129.1051090492, '부산광역시 금정구 체육공원로399번길 324', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/12/2504712_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/12/2504712_image3_1.jpg'),
  (295, '장산 (부산 국가지질공원)', 1, '부산 해운대구에 위치한 장산 (부산 국가지질공원)은 등산과 산책을 함께 즐길 수 있는 자연 명소입니다. 정상부에서는 부산 시가지와 바다가 한눈에 들어옵니다.', 9, 35.1811053657, 129.168189943, '부산광역시 해운대구 장산로 331-18', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', 'http://tong.visitkorea.or.kr/cms/resource/66/2661666_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/66/2661666_image3_1.jpg'),
  (296, '대연수목전시원', 1, '대연수목전시원은 부산 남구에 조성된 생태 공원입니다. 계절마다 바뀌는 식생과 산책로가 어우러져 가볍게 걷기 좋습니다.', 7, 35.1251964498, 129.0986919647, '부산광역시 남구 신선로447번길 24 (대연동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/56/2795656_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/56/2795656_image2_1.jpg'),
  (297, '부산 치유의 숲', 1, '부산 기장군의 부산 치유의 숲은 스파와 휴식 프로그램을 함께 즐길 수 있는 공간입니다. 방문 전 이용 요금과 운영 시간을 확인하는 것이 좋습니다.', 16, 35.2690086937, 129.1298103057, '부산광역시 기장군 철마면 철마천로 101', '09:00~22:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/30/2661730_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/30/2661730_image3_1.jpg'),
  (298, '공수어촌체험마을', 1, '공수어촌체험마을은 부산 기장군의 마을 자원을 활용한 체험 공간입니다. 지역 주민이 직접 운영하는 프로그램을 통해 일상과 맞닿은 부산을 만나볼 수 있습니다.', 16, 35.1844585662, 129.2111944455, '부산광역시 기장군 기장읍 공수해안길 13-2', '09:00~18:00 · 프로그램별 사전 예약제 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/32/2504632_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/32/2504632_image2_1.jpg'),
  (299, '회동수원지', 1, '부산 금정구에 자리한 회동수원지는 바다와 맞닿은 경관으로 사랑받는 곳입니다. 일출과 일몰 무렵의 풍경이 특히 인상적입니다.', 11, 35.2252550204, 129.116648768, '부산광역시 금정구 개좌로 147', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/72/2661472_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/72/2661472_image2_1.jpg'),
  (300, '영도 흰여울해안터널', 1, '영도 흰여울해안터널은 부산 영도구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 4, 35.0779590845, 129.0453201165, '부산광역시 영도구 영선동4가 1044-6', '상시 개방 · 연중무휴 · 무료', NULL, NULL);
INSERT INTO `place` (`id`, `name`, `type_id`, `description`, `district_id`, `latitude`, `longitude`, `address`, `operating_info`, `image_url_1`, `image_url_2`) VALUES
  (301, '곰내연밭', 1, '부산 기장군의 곰내연밭은 자연 학습과 휴식을 함께할 수 있는 공원입니다. 가족 단위 나들이 장소로 자주 찾는 곳입니다.', 16, 35.2954092493, 129.1695450043, '부산광역시 기장군 철마면 웅천리 254-4', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/58/2794158_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/58/2794158_image3_1.jpg'),
  (302, '미륵사(부산)', 1, '미륵사(부산)은 부산 금정구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 11, 35.274006634, 129.0489255467, '부산광역시 금정구 북문로 126 (금성동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/99/2687599_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/99/2687599_image3_1.jpg'),
  (303, '가덕도 연대봉', 1, '부산 강서구에 위치한 가덕도 연대봉은 등산과 산책을 함께 즐길 수 있는 자연 명소입니다. 정상부에서는 부산 시가지와 바다가 한눈에 들어옵니다.', 12, 35.0317518247, 128.8216713782, '부산광역시 강서구 천성동', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', NULL, NULL),
  (304, '스포원파크', 1, '스포원파크는 부산 금정구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 11, 35.289161567, 129.1070700628, '부산광역시 금정구 체육공원로399번길 324', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/25/3409925_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/25/3409925_image3_1.jpg'),
  (305, '금강공원', 1, '부산 동래구에 자리한 금강공원은 시민과 여행자가 함께 찾는 휴식 공간입니다. 계절에 따라 다른 분위기를 만날 수 있습니다.', 6, 35.2200354122, 129.0762190978, '부산광역시 동래구 우장춘로 155 (온천동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/12/3336512_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/12/3336512_image3_1.jpg'),
  (306, '동래향교', 1, '동래향교는 부산 동래구에 남아 있는 역사 유적입니다. 부산이 지나온 시간의 흔적을 현장에서 직접 확인할 수 있습니다.', 6, 35.2077202717, 129.0841215255, '부산광역시 동래구 동래로 103', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/25/3336525_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/25/3336525_image3_1.jpg'),
  (307, '초량교회', 1, '부산 동구의 초량교회는 오랜 시간 자리를 지켜 온 종교 유적입니다. 법회와 행사 일정에 따라 분위기가 달라집니다.', 3, 35.1171434347, 129.0369614421, '부산광역시 동구 초량상로 53 (초량동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/14/3343314_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/14/3343314_image3_1.jpg'),
  (308, '묘심사(부산)', 1, '묘심사(부산)은 부산 동구에 자리한 전통 사찰입니다. 고요한 경내와 주변 자연이 어우러져 차분한 시간을 보낼 수 있습니다.', 3, 35.126761849, 129.0395054026, '부산광역시 동구 망양로 671 (수정동)', '일출~일몰 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/32/3343332_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/32/3343332_image3_1.jpg'),
  (309, '친환경 스카이웨이 전망대(이바구길)', 1, '부산 동구에 위치한 친환경 스카이웨이 전망대(이바구길)에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 3, 35.1213095185, 129.0306535435, '부산광역시 동구 초량동', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/06/2720806_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/06/2720806_image3_1.jpg'),
  (310, '안데르센 동화마을', 1, '안데르센 동화마을은 부산 기장군의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 16, 35.3601199691, 129.2399148578, '부산광역시 기장군 장안읍 장안로 211', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/61/2795861_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/61/2795861_image3_1.jpg'),
  (311, '황령산', 1, '부산 남구에 위치한 황령산은 등산과 산책을 함께 즐길 수 있는 자연 명소입니다. 정상부에서는 부산 시가지와 바다가 한눈에 들어옵니다.', 7, 35.1579341561, 129.0827285679, '부산광역시 남구 황령산로 391-39 (대연동)', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', 'http://tong.visitkorea.or.kr/cms/resource/50/2732750_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/50/2732750_image3_1.jpg'),
  (312, '가덕도 등대', 1, '가덕도 등대는 부산 강서구의 전망 명소입니다. 도시와 바다가 함께 담기는 시야 덕분에 사진 촬영지로도 인기가 많습니다.', 12, 35.0006471157, 128.8295937487, '부산광역시 강서구 외양포로 10', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/81/3342781_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/81/3342781_image3_1.jpg'),
  (313, '렛츠런파크 부산경남', 1, '부산 강서구의 렛츠런파크 부산경남에서는 다양한 주제의 체험과 전시를 만날 수 있습니다. 프로그램에 따라 사전 예약이 필요할 수 있습니다.', 12, 35.1546447184, 128.8819239173, '부산광역시 강서구 가락대로 929 (범방동)', '10:00~18:00 · 매주 월요일 휴관 · 프로그램별 요금 상이', 'http://tong.visitkorea.or.kr/cms/resource/39/3350939_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/39/3350939_image3_1.jpg'),
  (314, '보람공원', 1, '보람공원은 부산 강서구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 12, 35.0881459047, 128.8432429784, '부산광역시 강서구 녹산산단262로14번길 20 (송정동)', '상시 개방 · 연중무휴 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/45/3337845_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/45/3337845_image3_1.jpg'),
