  (338, '아홉산숲', 1, '아홉산숲은 부산 기장군의 산림 명소입니다. 도심에서 가까우면서도 숲길과 능선을 따라 걷는 즐거움이 있는 곳입니다.', 16, 35.2871407693, 129.1715589466, '부산광역시 기장군 철마면 미동길 37-1', '상시 개방 · 연중무휴 · 무료 (일몰 후 산행 자제)', 'http://tong.visitkorea.or.kr/cms/resource/91/3309791_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/91/3309791_image3_1.jpg'),
  (339, '북맛골', 1, '부산 금정구에 위치한 북맛골은 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 11, 35.2369919623, 129.0825597462, '부산광역시 금정구 장전동', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/01/3336601_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/01/3336601_image3_1.jpg'),
  (340, '외양포 포진지', 1, '외양포 포진지는 부산 강서구에 남아 있는 역사 유적입니다. 부산이 지나온 시간의 흔적을 현장에서 직접 확인할 수 있습니다.', 12, 35.0056381443, 128.8251995524, '부산광역시 강서구 대항동', '09:00~18:00 · 매주 월요일 휴관 · 무료', 'http://tong.visitkorea.or.kr/cms/resource/03/3342803_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/03/3342803_image3_1.jpg'),
  (341, '동래온천길(온천천 카페거리)', 1, '부산 동래구에 위치한 동래온천길(온천천 카페거리)는 지역 특유의 분위기가 살아 있는 거리입니다. 골목마다 다른 가게와 풍경이 이어집니다.', 6, 35.1916279693, 129.1024592605, '부산광역시 동래구 온천천로 451 도시철도 온천장역(부산광역시 동래구 중앙대로 1520), 도시철도 동래역(부산광역시 동래구 중앙대로 1324), 온천천 카페거리(부산광역시 동래구 온천천로 451)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/33/2822333_image2_1.png', 'http://tong.visitkorea.or.kr/cms/resource/33/2822333_image3_1.png'),
  (342, '대항 어촌체험 휴양마을', 1, '대항 어촌체험 휴양마을은 부산 강서구의 마을 자원을 활용한 체험 공간입니다. 지역 주민이 직접 운영하는 프로그램을 통해 일상과 맞닿은 부산을 만나볼 수 있습니다.', 12, 35.0117208424, 128.8276908389, '부산광역시 강서구 가덕해안로1207번길 9-2', '09:00~18:00 · 프로그램별 사전 예약제 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/26/2607126_image2_1.bmp', 'http://tong.visitkorea.or.kr/cms/resource/26/2607126_image3_1.bmp'),
  (343, '플루니티', 1, '부산 영도구에 위치한 플루니티는 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 4, 35.0923685831, 129.0452947259, '부산광역시 영도구 번영길 8', '10:00~19:00 · 연중무휴 · 유료', NULL, NULL),
  (344, 'UN조각공원', 1, 'UN조각공원은 부산 남구의 도심 공원입니다. 산책로와 휴식 공간이 잘 갖춰져 있어 일상 가까이에서 여유를 찾을 수 있습니다.', 7, 35.1297375886, 129.0976280442, '부산광역시 남구 대연동 93', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (345, '영화의전당 라이브러리 자료실', 1, '부산 해운대구의 영화의전당 라이브러리 자료실은 문화 콘텐츠를 다양하게 경험할 수 있는 공간입니다. 프로그램 일정에 따라 방문 계획을 세우면 좋습니다.', 9, 35.1710029572, 129.1270687971, '부산광역시 해운대구 수영강변대로 120 (우동)', '10:00~19:00 · 매주 월요일 휴관', 'http://tong.visitkorea.or.kr/cms/resource/99/3453999_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/99/3453999_image3_1.jpg'),
  (346, '커넥트현대', 1, '커넥트현대는 부산 동구에 위치한 복합문화공간입니다. 전시와 공연, 여가 프로그램이 한곳에서 운영됩니다.', 3, 35.1413411243, 129.0586005649, '부산광역시 동구 범일로 125 (범일동)', '10:00~19:00 · 매주 월요일 휴관', 'http://tong.visitkorea.or.kr/cms/resource/06/3451506_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/06/3451506_image3_1.jpg'),
  (347, '그런고로', 1, '부산 부산진구에 위치한 그런고로는 독특한 테마와 체험 요소로 알려진 곳입니다. 일정 중 색다른 시간을 보내고 싶을 때 들르기 좋습니다.', 5, 35.1575588567, 129.0642468527, '부산광역시 부산진구 서전로 40 (전포동)', '10:00~19:00 · 연중무휴 · 유료', 'http://tong.visitkorea.or.kr/cms/resource/96/3421696_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/96/3421696_image3_1.jpg'),
  (348, '감지해변', 1, '감지해변은 부산 영도구의 바다를 대표하는 명소입니다. 탁 트인 수평선과 해안 풍경이 사계절 내내 방문객을 맞이합니다.', 4, 35.0625336062, 129.0764900502, '부산광역시 영도구 감지길 110 (동삼동)', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (349, '영주하늘눈전망대', 1, '부산 중구에 위치한 영주하늘눈전망대에서는 부산의 풍경을 한눈에 조망할 수 있습니다. 해 질 무렵 방문하면 야경까지 함께 즐길 수 있습니다.', 1, 35.1146102693, 129.0307259427, '부산광역시 중구 영주동 91-7 (영주동)', '상시 개방 · 연중무휴 · 무료', NULL, NULL),
  (350, '산복도로', 1, '산복도로는 부산 중구의 개성 있는 거리입니다. 카페와 상점, 골목 풍경이 어우러져 걸으며 둘러보는 재미가 있습니다.', 1, 35.1092330974, 129.0309232942, '부산광역시 중구 (영주동)', '상시 개방 · 점포별 운영 시간 상이', 'http://tong.visitkorea.or.kr/cms/resource/16/3343716_image2_1.jpg', 'http://tong.visitkorea.or.kr/cms/resource/16/3343716_image3_1.jpg');
INSERT INTO `place` (`id`, `name`, `type_id`, `description`, `district_id`, `latitude`, `longitude`, `address`, `operating_info`, `image_url_1`, `image_url_2`) VALUES
  (351, '2026 부산국제불교박람회', 2, '부산 해운대구에서 열리는 2026 부산국제불교박람회는 주제형 행사·전시 프로그램입니다. 방문 전 운영 기간을 확인하는 것이 좋습니다.', 9, 35.1687048508, 129.1354937071, '부산광역시 해운대구 APEC로 55 (우동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 02-2231-2011', 'https://tong.visitkorea.or.kr/cms/resource/92/4077792_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/92/4077792_image3_1.jpg'),
  (352, '2026 나이트레이스 인 부산', 2, '2026 나이트레이스 인 부산은 부산 수영구에서 개최되는 행사입니다. 기간 중 전시와 부대 프로그램이 함께 운영됩니다.', 14, 35.1537727886, 129.1185199367, '부산광역시 수영구 광안해변로 219 (광안동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-740-4116', 'https://tong.visitkorea.or.kr/cms/resource/41/4065341_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/41/4065341_image3_1.jpg'),
  (353, '제48차 유네스코 세계유산위원회 특별공연 산화비 : HEXAGRAM 22', 2, '부산 해운대구에서 진행되는 제48차 유네스코 세계유산위원회 특별공연 산화비 : HEXAGRAM 22는 무대 공연 프로그램입니다. 공연 일정은 주최 측 안내에 따라 변경될 수 있습니다.', 9, 35.1690637155, 129.1360182683, '부산광역시 해운대구 APEC로 55 (우동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 02-2039-0342', 'https://tong.visitkorea.or.kr/cms/resource/57/4077757_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/57/4077757_image3_1.jpg'),
  (354, '부산국제록페스티벌', 2, '부산국제록페스티벌은 부산 사상구에서 열리는 지역 축제입니다. 지역의 색이 담긴 프로그램과 무대가 기간 중 이어집니다.', 15, 35.1728573, 128.9681914, '부산광역시 사상구 삼락동 29-50', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-713-5000', 'https://tong.visitkorea.or.kr/cms/resource/06/4040606_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/06/4040606_image3_1.jpg'),
  (355, '부산항축제', 2, '부산 동구에서 개최되는 부산항축제는 방문객이 함께 즐기는 축제입니다. 상세 일정과 프로그램은 해마다 달라질 수 있습니다.', 3, 35.1144041132, 129.0464193172, '부산광역시 동구 이순신대로 164 (초량동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-713-5000', 'https://tong.visitkorea.or.kr/cms/resource/70/4058670_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/70/4058670_image3_1.jpg'),
  (356, '광안리어방축제', 2, '광안리어방축제는 부산 수영구에서 열리는 지역 축제입니다. 지역의 색이 담긴 프로그램과 무대가 기간 중 이어집니다.', 14, 35.1537727886, 129.1185199367, '부산광역시 수영구 광안해변로 219 (광안동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-610-4212', 'https://tong.visitkorea.or.kr/cms/resource/10/4066810_image2_1.JPG', 'https://tong.visitkorea.or.kr/cms/resource/10/4066810_image3_1.JPG'),
  (357, '2026 부산나이트워크42K', 2, '부산 해운대구에서 열리는 2026 부산나이트워크42K는 주제형 행사·전시 프로그램입니다. 방문 전 운영 기간을 확인하는 것이 좋습니다.', 9, 35.16790821788159, 129.1273173184388, '부산광역시 해운대구 수영강변대로 85 (우동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 070-4705-2008', 'https://tong.visitkorea.or.kr/cms/resource/37/4069137_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/37/4069137_image3_1.jpg'),
  (358, '2026 부산바다도서관', 2, '2026 부산바다도서관은 부산 수영구에서 개최되는 행사입니다. 기간 중 전시와 부대 프로그램이 함께 운영됩니다.', 14, 35.154689, 129.132986, '부산광역시 수영구 민락동 110-19', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-745-7288', 'https://tong.visitkorea.or.kr/cms/resource/73/4070173_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/73/4070173_image3_1.jpg'),
  (359, '2026 용골 댄스 페스타', 2, '부산 중구에서 열리는 2026 용골 댄스 페스타는 주제형 행사·전시 프로그램입니다. 방문 전 운영 기간을 확인하는 것이 좋습니다.', 1, 35.100929432638, 129.032442805252, '부산광역시 중구 용두산길 37-55 (광복동2가)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-714-4674', 'https://tong.visitkorea.or.kr/cms/resource/73/4067473_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/73/4067473_image3_1.jpg'),
  (360, '세계유산위원회 대한민국관(K-Heritage House)', 2, '세계유산위원회 대한민국관(K-Heritage House)는 부산 해운대구에서 개최되는 행사입니다. 기간 중 전시와 부대 프로그램이 함께 운영됩니다.', 9, 35.1690637154991, 129.136018268316, '부산광역시 해운대구 APEC로 55 (우동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 042-481-4833', 'https://tong.visitkorea.or.kr/cms/resource/26/4055726_image2_1.jpeg', 'https://tong.visitkorea.or.kr/cms/resource/26/4055726_image3_1.jpeg'),
  (361, '부산 밀 페스티벌', 2, '부산 북구에서 개최되는 부산 밀 페스티벌은 방문객이 함께 즐기는 축제입니다. 상세 일정과 프로그램은 해마다 달라질 수 있습니다.', 8, 35.2163777948624, 128.999546395503, '부산광역시 북구 덕천동 763 북구 화명생태공원', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-713-5000', 'https://tong.visitkorea.or.kr/cms/resource/30/4054930_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/30/4054930_image3_1.jpg'),
  (362, '포트빌리지 부산 2026', 2, '포트빌리지 부산 2026은 부산 중구에서 개최되는 행사입니다. 기간 중 전시와 부대 프로그램이 함께 운영됩니다.', 1, 35.104388, 129.041338, '부산광역시 중구 중앙동4가 15-33 부산항 제1부두', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 070-4680-1718', 'https://tong.visitkorea.or.kr/cms/resource/81/4065381_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/81/4065381_image3_1.jpg'),
  (363, '2026 부산푸드필름페스타', 2, '부산 해운대구에서 진행되는 2026 부산푸드필름페스타는 무대 공연 프로그램입니다. 공연 일정은 주최 측 안내에 따라 변경될 수 있습니다.', 9, 35.170963130477155, 129.12704224730075, '부산광역시 해운대구 수영강변대로 120 (우동)', '행사 기간 중 운영 · 상세 일정 매년 변동 · 문의 051-710-6948', 'https://tong.visitkorea.or.kr/cms/resource/90/4065290_image2_1.jpg', 'https://tong.visitkorea.or.kr/cms/resource/90/4065290_image3_1.jpg'),
